mapper.select:
SELECT EAS.ID AS SCOPE_ID, EAS.NAME AS SCOPE_NAME, SU.ID AS STUDENT_ID, SU.ACCT AS STUDENT_ACCT, SU.REAL_NAME AS STUDENT_NAME, SU.NICKNAME AS NICK_NAME, ESA.PAPERS_ID AS PAPER_ID, EP.TOTLE_SCORE AS TOTAL_SCORE, EP.EXAM_POLICY_ID AS POLICY_ID, ESA.ID AS STUDENT_ANSWER_ID, ESA.SCORE AS OBJECTIVE_QUESTION_SCORE, ESA.REVIEW_STATUS AS REVIEW_STATUS, EPY.EXAM_TIME_START AS EXAM_TIME, EPY.NAME AS PAPER_NAME, EPY.PASS_SCORE AS PASS_SCORE FROM EXAM_POLICY EPY, EXAM.APP_SCOPE EAS, EXAM_SCOPE_POLICY_REL ESPR, EXAM_PAPER EP, EXAM_STUDENT_ANSWER ESA, APP_SCOPE_USER_REL SUR, SYS_USER SU WHERE EAS.ID=SUR.SCOPE_ID AND EP.ID=ESA.PAPERS_ID AND SU.ID=ESA.STUDENT_ID AND SU.ID=SUR.USER_ID AND ESPR.SCOPE_ID=EAS."ID" AND ESPR.POLICY_ID=EP.EXAM_POLICY_ID AND EPY.ID=EP.EXAM_POLICY_ID AND ESA.ENABLED_FLAG=1 AND SU.ENABLED_FLAG=1 AND EP.ENABLED_FLAG=1 AND ESA.STATUS=1
AND upper(SU.REAL_NAME) like upper('%${bo.studentName}%')
AND ESA.REVIEW_STATUS=#{bo.reviewStatus}
AND EAS.ID=#{bo.scopeId}
ORDER BY ESA.IDDESC
